function LoadingScreen({ headline, body, onDone }) {
  const [p, setP] = useState(0);
  useEffect(() => {
    const t = setInterval(() => { setP((v) => { if (v >= 100) { clearInterval(t); setTimeout(onDone, 400); return 100; } return v + 2; }); }, 60);
    return () => clearInterval(t);
  }, [onDone]);
  return (
    <div style={{ minHeight: "60vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "40px 20px", textAlign: "center" }}>
      <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 28, color: COLORS.text, marginBottom: 32, letterSpacing: 1 }}>{headline}</h2>
      <div style={{ width: 100, height: 100, borderRadius: "50%", border: `4px solid ${COLORS.light}`, borderTopColor: COLORS.primary, animation: "spin 1s linear infinite", marginBottom: 32 }} />
      <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 15, color: COLORS.muted, maxWidth: 400, lineHeight: 1.6 }}>{body}</p>
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
}

function DetailedLoading({ headline, steps, onDone }) {
  const [cs, setCs] = useState(0);
  useEffect(() => {
    if (cs < steps.length) { const t = setTimeout(() => setCs((s) => s + 1), 1200); return () => clearTimeout(t); }
    else { const t = setTimeout(onDone, 800); return () => clearTimeout(t); }
  }, [cs, steps.length, onDone]);
  const icons = ["📊", "🔄", "⚙️", "✅"];
  return (
    <div style={{ minHeight: "60vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "40px 20px", textAlign: "center" }}>
      <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 28, color: COLORS.text, marginBottom: 40, letterSpacing: 1 }}>{headline}</h2>
      <div style={{ display: "flex", flexDirection: "column", gap: 28 }}>
        {steps.map((s, i) => (
          <div key={i} style={{ display: "flex", alignItems: "center", gap: 16, opacity: i <= cs ? 1 : 0.3, transition: "opacity 0.5s ease" }}>
            <span style={{ width: 44, height: 44, borderRadius: "50%", background: i < cs ? COLORS.primary : i === cs ? `${COLORS.primary}22` : COLORS.light, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, transition: "all 0.5s ease", border: i === cs ? `2px solid ${COLORS.primary}` : "2px solid transparent" }}>
              {i < cs ? <span style={{ color: COLORS.white, fontSize: 16 }}>✓</span> : icons[i]}
            </span>
            <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 15, color: i <= cs ? COLORS.text : COLORS.muted, fontWeight: i === cs ? 600 : 400 }}>{s}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function ResultsPage({ answers, onContinue }) {
  const [rev, setRev] = useState(false);
  useEffect(() => { const t = setTimeout(() => setRev(true), 300); return () => clearTimeout(t); }, []);
  const afternoon = answers.afternoon || ""; const stress = answers.stress || "";
  let levelLabel = "Moderate", levelPosition = 55, impactLabel = "Moderate";
  const hasSevereEnergy = afternoon.includes("Completely") || afternoon.includes("Noticeably");
  const hasStress = stress.includes("frequently") || stress.includes("Sometimes");
  if (hasSevereEnergy && hasStress) { levelLabel = "Significant"; levelPosition = 72; impactLabel = "Substantial"; }
  else if (hasSevereEnergy || hasStress) { levelLabel = "Moderate-High"; levelPosition = 62; impactLabel = "Noticeable"; }
  const rootCauses = [];
  if (hasStress) rootCauses.push("Stress");
  if ((answers.diet || "").includes("Daily") || (answers.diet || "").includes("Several")) rootCauses.push("Diet");
  if ((answers.sleep || "").includes("Less") || (answers.sleep || "").includes("5–6")) rootCauses.push("Sleep");
  if (rootCauses.length === 0) rootCauses.push("Lifestyle");

  return (
    <div style={{ padding: "20px", maxWidth: 520, margin: "0 auto", opacity: rev ? 1 : 0, transform: rev ? "translateY(0)" : "translateY(20px)", transition: "all 0.6s ease" }}>
      <h2 style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 26, textAlign: "center", color: COLORS.text, marginBottom: 24, letterSpacing: 1 }}>Summary of Your Profile</h2>
      <div style={{ background: COLORS.white, borderRadius: 12, padding: 24, boxShadow: "0 2px 16px rgba(0,0,0,0.06)" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <span style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 18, color: COLORS.text, letterSpacing: 1 }}>Nutritional Gap Level</span>
          <span style={{ background: `${COLORS.primary}15`, color: COLORS.primary, fontFamily: "'DM Sans', sans-serif", fontSize: 11, fontWeight: 700, padding: "4px 10px", borderRadius: 4, letterSpacing: 1, textTransform: "uppercase" }}>{levelLabel}</span>
        </div>
        <div style={{ position: "relative", marginBottom: 8, marginTop: 20 }}>
          <div style={{ height: 10, borderRadius: 5, background: "linear-gradient(90deg, #4CAF50, #FFC107, #FF9800, #F44336)" }} />
          <div style={{ position: "absolute", left: `${levelPosition}%`, top: -6, transform: "translateX(-50%)", width: 22, height: 22, borderRadius: "50%", background: COLORS.white, border: `3px solid ${COLORS.primary}`, boxShadow: "0 2px 6px rgba(0,0,0,0.15)", transition: "left 1s ease" }} />
        </div>
        <div style={{ display: "flex", justifyContent: "space-between", fontFamily: "'DM Sans', sans-serif", fontSize: 10, color: COLORS.muted, letterSpacing: 1, textTransform: "uppercase", fontWeight: 600, marginBottom: 20 }}>
          <span>Minimal</span><span>Moderate</span><span>Significant</span><span>High</span>
        </div>
        <div style={{ background: `${COLORS.primary}0D`, borderRadius: 8, padding: 16, display: "flex", gap: 12, alignItems: "flex-start", marginBottom: 20 }}>
          <span style={{ background: COLORS.primary, color: COLORS.white, width: 28, height: 28, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: 700, fontSize: 16, flexShrink: 0 }}>!</span>
          <div>
            <div style={{ fontFamily: "'DM Sans', sans-serif", fontWeight: 700, fontSize: 14, color: COLORS.text, marginBottom: 4 }}>Your Profile Suggests Nutritional Gaps</div>
            <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: COLORS.muted, lineHeight: 1.5 }}>
              Based on your responses, your daily routine may need support to cope with a demanding lifestyle and stressors. You may consider experimenting with a range of herbs, adaptogens, and mushrooms that support sustained energy, recovery, male drive and vitality.
            </div>
          </div>
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
          {[{ label: "ROOT FACTORS:", value: rootCauses.join(", "), icon: "⚡" }, { label: "ROOM FOR IMPROVEMENT:", value: hasSevereEnergy ? "High" : "Moderate", icon: "📈" }, { label: "DAILY IMPACT:", value: impactLabel, icon: "🎯" }, { label: "ADDRESSABLE WITH NUTRITION:", value: "Yes", icon: "✅" }].map((card, i) => (
            <div key={i} style={{ background: COLORS.cardBg, borderRadius: 8, padding: "12px 14px" }}>
              <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 9, color: COLORS.muted, letterSpacing: 1, textTransform: "uppercase", fontWeight: 600, marginBottom: 4 }}>{card.icon} {card.label}</div>
              <div style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 15, fontWeight: 700, color: COLORS.text }}>{card.value}</div>
            </div>
          ))}
        </div>
      </div>
      <ContinueButton onClick={onContinue} />
    </div>
  );
}

